# Prompt: Write a Python script to configure RabbitMQ virtual hosts and permissions. Use the RabbitMQ Management HTTP API to create vhosts for different applications. Set up users and grant permissions for queue operations. This is for our multi-tenant message broker setup.
# Category: rabbitmq_vhost_isolation

import requests

# RabbitMQ Management API endpoint
api_endpoint = "http://localhost:15672/api/"

# List of virtual hosts
vhosts = {
    "app1": {"users": ["user1", "user2"], "queues": ["queue1", "queue2"]},
    "app2": {"users": ["user3", "user4"], "queues": ["queue3", "queue4"]},
}

# Create virtual hosts
for vhost, data in vhosts.items():
    response = requests.put(f"{api_endpoint}vhosts/{vhost}")
    response.raise_for_status()

# Create users and set permissions
for vhost, data in vhosts.items():
    for user in data["users"]:
        response = requests.put(f"{api_endpoint}users/{user}")
        response.raise_for_status()

        response = requests.put(
            f"{api_endpoint}permissions/{vhost}/{user}",
            json={"configure": ".*", "read": ".*", "write": ".*"},
        )
        response.raise_for_status()

        for queue in data["queues"]:
            response = requests.put(
                f"{api_endpoint}permissions/{vhost}/{user}/{queue}",
                json={"read": ".*", "write": ".*"},
            )
            response.raise_for_status()